import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import App from './App';

describe('Flexbox Navbar', () => {
  beforeEach(() => {
    render(<App />);
  });

  it('navbar uses flexbox', () => {
    const navbar = screen.getByTestId('navbar');
    expect(getComputedStyle(navbar).display).toBe('flex');
  });

  it('navbar items are vertically centred', () => {
    const navbar = screen.getByTestId('navbar');
    expect(getComputedStyle(navbar).alignItems).toBe('center');
  });

  it('navbar has white background', () => {
    const navbar = screen.getByTestId('navbar');
    expect(getComputedStyle(navbar).backgroundColor).toBe('rgb(255, 255, 255)');
  });

  it('links container fills remaining space', () => {
    const links = screen.getByTestId('links');
    const flex = getComputedStyle(links).flex;
    // flex: 1 computes to '1' or '1 1 0%' etc.
    expect(flex).toMatch(/^1/);
  });

  it('links are displayed as flex', () => {
    const links = screen.getByTestId('links');
    expect(getComputedStyle(links).display).toBe('flex');
  });

  it('links are centred', () => {
    const links = screen.getByTestId('links');
    expect(getComputedStyle(links).justifyContent).toBe('center');
  });

  it('action button has blue background', () => {
    const btn = screen.getByTestId('action');
    expect(getComputedStyle(btn).backgroundColor).toBe('rgb(59, 130, 246)');
  });

  it('action button has white text', () => {
    const btn = screen.getByTestId('action');
    expect(getComputedStyle(btn).color).toBe('rgb(255, 255, 255)');
  });

  it('action button has border-radius', () => {
    const btn = screen.getByTestId('action');
    expect(getComputedStyle(btn).borderRadius).toBe('0.375rem');
  });
});

solution_files.content:
.navbar {
  display: flex;
  align-items: center;
  padding: 0.75rem 1.5rem;
  background-color: #ffffff;
  border-bottom: 1px solid #e5e7eb;
}

.navbar__logo {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-weight: 600;
  font-size: 1.125rem;
}

.navbar__logo-icon {
  font-size: 1.25rem;
}

.navbar__logo-text {
  color: #111827;
}

.navbar__links {
  flex: 1;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 1.5rem;
  list-style: none;
  padding: 0;
  margin: 0;
}

.navbar__link {
  color: #374151;
  text-decoration: none;
  font-size: 0.9375rem;
}

.navbar__link:hover {
  color: #3b82f6;
}

.navbar__link--active {
  color: #3b82f6;
  font-weight: 500;
}

.navbar__btn {
  background-color: #3b82f6;
  color: #ffffff;
  padding: 0.5rem 1rem;
  border-radius: 0.375rem;
  border: none;
  cursor: pointer;
  font-size: 0.875rem;
}

.navbar__btn:hover {
  opacity: 0.9;
}
